// Get all reports
const reports = items[0].json.reports.report;

// Calculate yesterday date in UTC
const yesterday = new Date();
yesterday.setUTCDate(yesterday.getUTCDate() - 1);

// Format YYYYMMDD
const yyyy = yesterday.getUTCFullYear();
const mm = String(yesterday.getUTCMonth() + 1).padStart(2, '0');
const dd = String(yesterday.getUTCDate()).padStart(2, '0');
const ymd = `${yyyy}${mm}${dd}`;

// Filter yesterday's Daily transaction report
const result = reports.filter(r =>
  r.description === 'Daily transaction report'&&
  r.file2 &&
  r.file2.includes(ymd)
);

return result.map(r => ({ json: r }));

