DECLARE @json NVARCHAR(MAX);
SET @json = N'{{$json["transactionsJson"]}}';

-- IMPORTANT: terminate statement before OPENJSON
;

INSERT INTO authorised_transactions (
    column1, column2, column3, column4 
)
SELECT
    column1,
    column2,
    column3,
    column4,
FROM OPENJSON(@json)
WITH (
    column1 NVARCHAR(50),
    column2 NVARCHAR(50),
    column3 NVARCHAR(MAX),
    column4 NVARCHAR(20)
) t
WHERE NOT EXISTS (
    SELECT 1
    FROM authorised_transactions_dates d
    WHERE d.transaction_date = CONVERT(date, t.transaction_date, 103)
);

INSERT INTO authorised_transactions_dates (transaction_date)
SELECT DISTINCT CONVERT(date, JSON_VALUE(value, '$.transaction_date'), 103)
FROM OPENJSON(@json)
WHERE NOT EXISTS (
    SELECT 1 
    FROM authorised_transactions_dates d 
    WHERE d.transaction_date = CONVERT(date, JSON_VALUE(value, '$.transaction_date'), 103)
);

SELECT 'SUCCESS' AS result;
